func (s *transactionServer) CreateTransaction(ctx context.Context, req *transactionpb.CreateTransactionRequest) (*transactionpb.CreateTransactionResponse, error) {
	if req == nil {
		return nil, status.Error(codes.InvalidArgument, "request is required")
	}
	if req.GetFromAccountId() == "" || req.GetToAccountId() == "" {
		return nil, status.Error(codes.InvalidArgument, "from_account_id and to_account_id are required")
	}
	if req.GetFromAccountId() == req.GetToAccountId() {
		return nil, status.Error(codes.InvalidArgument, "source and destination accounts must differ")
	}
	if req.GetAmount() <= 0 {
		return nil, status.Error(codes.InvalidArgument, "amount must be greater than zero")
	}
	if req.GetCurrency() == "" {
		return nil, status.Error(codes.InvalidArgument, "currency is required")
	}
	if req.GetIdempotencyKey() == "" {
		return nil, status.Error(codes.InvalidArgument, "idempotency_key is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	if existing, ok := s.idempotencyLog[req.GetIdempotencyKey()]; ok {
		return &transactionpb.CreateTransactionResponse{
			TransactionId: existing.TransactionID,
			Status:        existing.Status,
			FromBalance:   existing.FromBalance,
			ToBalance:     existing.ToBalance,
		}, nil
	}

	fromAcct, ok := s.accounts[req.GetFromAccountId()]
	if !ok {
		return nil, status.Error(codes.NotFound, "from account not found")
	}
	toAcct, ok := s.accounts[req.GetToAccountId()]
	if !ok {
		return nil, status.Error(codes.NotFound, "to account not found")
	}
	if fromAcct.Currency != req.GetCurrency() || toAcct.Currency != req.GetCurrency() {
		return nil, status.Error(codes.FailedPrecondition, "currency mismatch")
	}
	if fromAcct.Balance < req.GetAmount() {
		return nil, status.Error(codes.FailedPrecondition, "insufficient funds")
	}

	fromAcct.Balance -= req.GetAmount()
	toAcct.Balance += req.GetAmount()

	txID := s.nextTransactionID()
	record := &transactionRecord{
		TransactionID: txID,
		FromAccountID: req.GetFromAccountId(),
		ToAccountID:   req.GetToAccountId(),
		Amount:        req.GetAmount(),
		Currency:      req.GetCurrency(),
		Status:        "COMPLETED",
		FromBalance:   fromAcct.Balance,
		ToBalance:     toAcct.Balance,
	}
	s.idempotencyLog[req.GetIdempotencyKey()] = record

	return &transactionpb.CreateTransactionResponse{
		TransactionId: record.TransactionID,
		Status:        record.Status,
		FromBalance:   record.FromBalance,
		ToBalance:     record.ToBalance,
	}, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *transactionpb.GetBalanceRequest) (*transactionpb.GetBalanceResponse, error) {
	if req == nil || req.GetAccountId() == "" {
		return nil, status.Error(codes.InvalidArgument, "account_id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	acct, ok := s.accounts[req.GetAccountId()]
	if !ok {
		return nil, status.Error(codes.NotFound, "account not found")
	}

	return &transactionpb.GetBalanceResponse{
		AccountId: req.GetAccountId(),
		Balance:   acct.Balance,
		Currency:  acct.Currency,
	}, nil
}

func (s *transactionServer) nextTransactionID() string {
	n := atomic.AddUint64(&s.seq, 1)
	return "tx_" + itoa(n)
}

func itoa(v uint64) string {
	if v == 0 {
		return "0"
	}
	var buf [20]byte
	i := len(buf)
	for v > 0 {
		i--
		buf[i] = byte('0' + v%10)
		v /= 10
	}
	return string(buf[i:])
}

